// src/pages/ResultsPage.js
import React from "react";
import "./ResultsPage.css";

function RecordingBanner({ duration, scenario }) {
  const fmt = (s) =>
    `${Math.floor(s / 60)
      .toString()
      .padStart(2, "0")}:${(s % 60).toString().padStart(2, "0")}`;

  return (
    <div className="recording-banner">
      <div className="recording-left">
        <div className="recording-icon">🎤</div>
        <div>
          <div className="recording-title">Your Recording</div>
          <div className="recording-sub">
            {scenario || "General Speaking"} • {fmt(duration || 0)}
          </div>
        </div>
      </div>

      <button className="recording-play">▶</button>
    </div>
  );
}

function HighlightedTranscript({
  transcript,
  fillerBreakdown = {},
  lowConfidenceWords = [],
}) {
  if (!transcript) return <p>No transcript available.</p>;

  const words = transcript.split(" ");

  return (
    <p className="transcript-text">
      {words.map((word, i) => {
        const clean = word.toLowerCase().replace(/[.,!?]/g, "");

        if (fillerBreakdown[clean]) {
          return (
            <mark key={i} className="filler-word">
              {word}{" "}
            </mark>
          );
        }

        if (lowConfidenceWords.includes(clean)) {
          return (
            <mark key={i} className="unclear-word">
              {word}{" "}
            </mark>
          );
        }

        return word + " ";
      })}
    </p>
  );
}

export default function ResultsPage({ results, navigate }) {
  if (!results) {
    return (
      <div className="results-root">
        <div className="results-inner">
          <p>No results found.</p>
        </div>
      </div>
    );
  }

  const { transcript, metrics, fillers, pronunciation, scenario } = results;

  const lowConfidenceWords =
    pronunciation?.lowConfidenceWords || [];

  const hasFillers = fillers?.total > 0;

  return (
    <div className="results-root">
      <div className="results-inner">

        {/* Back Button */}
        <button
          className="results-back"
          onClick={() => navigate("dashboard")}
        >
          ← Back to Dashboard
        </button>

        {/* ① Recording */}
        <RecordingBanner
          duration={metrics?.duration}
          scenario={scenario}
        />

        {/* ② TRANSCRIPT (MOVED HERE) */}
        <div className="card transcript-section">
          <div className="transcript-header-row">
            <span className="transcript-title">📝 Your Transcript</span>

            <div className="transcript-legend">
              {hasFillers && (
                <mark className="legend-mark filler-legend">
                  filler word
                </mark>
              )}

              {lowConfidenceWords.length > 0 && (
                <mark className="legend-mark pronunciation-legend">
                  unclear word
                </mark>
              )}
            </div>
          </div>

          <div className="transcript-body-open">
            <HighlightedTranscript
              transcript={transcript}
              fillerBreakdown={fillers?.breakdown}
              lowConfidenceWords={lowConfidenceWords}
            />
          </div>
        </div>

        {/* ③ SCORE */}
        <div className="score-row">
          <div className="score-card">
            <h3>Overall Score</h3>
            <div className="score-value">
              {metrics?.score || 0}
            </div>
          </div>
        </div>

        {/* ④ METRICS */}
        <div className="metrics-row">
          <div className="metric-card">
            <h4>WPM</h4>
            <p>{metrics?.wpm || 0}</p>
          </div>

          <div className="metric-card">
            <h4>Fillers</h4>
            <p>{fillers?.total || 0}</p>
          </div>

          <div className="metric-card">
            <h4>Duration</h4>
            <p>{metrics?.duration || 0}s</p>
          </div>
        </div>

        {/* ⑤ COACH */}
        <div className="card">
          <h3>AI Feedback</h3>
          <p>
            {results.feedback ||
              "Keep practicing and improving your clarity and pacing."}
          </p>
        </div>

      </div>
    </div>
  );
}
